import articles from '../fixtures'
import {DELETE_ARTICLE, REVERT_ARTICLES} from '../types'

const initialState = {}

export default function (initialState = articles, action) {
    switch (action.type) {
        case DELETE_ARTICLE:
            return initialState.filter(article => article.id !== action.payload.id)
        case REVERT_ARTICLES:
            return initialState.slice().reverse()
        default:
            return initialState
    }
}
